#include <bits/stdc++.h>
using namespace std;vector<int>ch[55];bool del[55];int n;
void rm(int u){del[u]=true;for(int v:ch[u])rm(v);}
int main(){cin>>n;int root=-1;for(int i=0;i<n;i++){int p;cin>>p;if(p==-1)root=i;else ch[p].push_back(i);}int d;cin>>d;rm(d);int cnt=0;for(int i=0;i<n;i++){if(del[i])continue;int c=0;for(int v:ch[i])if(!del[v])c++;if(c==0)cnt++;}cout<<cnt<<"\n";}
